import { applyAvatar, getAvatars, getAvatarFolderName } from "./avatars";
import { setExpression } from "./expressions";
import { stateStore } from "./state";

/**
 * Called when a chat session is started
 */
chat.addEventListener("init", (e) => {
  if(chat.variables.view) {
    chat.appTrigger('SelectView', chat.variables.view);
  }
  chat.characters.forEach((c) => {
    const folder = getAvatarFolderName(c);
    if(folder) {
      applyAvatar(c, 'Idle')
    }
  });
  if(chat.variables.background) {
    chat.appTrigger('SetBackgroundFromScenario', chat.variables.background);
  }
});

/**
 * Called at the beginning of a new chat
 */
chat.addEventListener("start", (e) => {
  const avatars = getAvatars(chat.character, "Idle", "Neutral");
  if(avatars.length) {
    chat.appTrigger("SelectView", "portrait");
  }
});

/**
 * Called when a reply is being generated
 */
chat.addEventListener("generating", (e) => {
  stateStore.setSpeaking(true);
  setExpression(e.character, "Neutral");
  applyAvatar(e.character, "Thinking");
});

/**
 * Called at the start of each sentence being spoken
 */
chat.addEventListener("speechStart", (e) => {
  applyAvatar(e.character, e.isNarrator ? "Idle" : "Talking");
});

/**
 * Called when all sentences of a reply has been spoken
 */
chat.addEventListener("speechComplete", (e) => {
  stateStore.setSpeaking(false);
  applyAvatar(e.character, "Idle");
});"},{"name":"utils","content":"/**
