import { randomly } from "./utils";
import { applyAvatar } from "./avatars";
import { stateStore } from "./state";
import { setExpression } from "./expressions";
import { log } from "./logging";

/**
 * Creates a Voxta trigger that changes the current emotion
 * and updates the avatar
 * @param {string} e - Voxta Event
 * @param {object} opts - The options: { emojis: [], color: string, expression: string }
 */
export const createEmoteTrigger = (opts) => (e) => {
  // Emojis
  const emojis = opts.emojis ?? [];
  const emoji = randomly(emojis);
  const color = opts.color;
  chat.appTrigger("Emote", emoji, color);

  // Expressions (saved in chat)
  setExpression(e.character, opts.expression);

  // Update the avatar if applicable
  if(!stateStore.speaking)
    applyAvatar(e.character, "Idle");
  else
    log(() => "Avatar expression skipped because speech is in progress: " + chat.variables.expression);
}"},{"name":"avatars","content":"import { chat } from "@voxta";
import { randomly } from "./utils";
import { getExpression } from "./expressions";
import { log } from "./logging";
import { stateStore } from "./state";

const lastAvatar = { value: '' };

export function getAvatarFolderName(character) {
  const key = 'avatars_' + character.id;
  return chat.variables[key];
}

export function setAvatarFolderName(character, folder) {
  const key = 'avatars_' + character.id;
  if(!folder) {
    delete chat.variables[key];
    console.log('removed folder')
  } else {
    chat.variables[key] = folder;
    console.log('set folder ' + key + ' = ' + folder)
  }
}

/**
 * Lists available avatars for a given expression and state
 * @param {Character} character - The character
 * @param {string} expression - The expression string, defaults to Neutral
 * @param {string} state - The state string (Idle, Thinking, Talking)
 */
export function getAvatars(character, state, expression) {
  if(!expression) expression = getExpression(character);
  const folder = chat.variables['avatars_' + character.id];
  if(folder)
  {
    // List folder avatars
    let availableAvatars = character.assets.matchFiles(`^Avatars/${folder}/${expression}_${state}(_[A-Z][a-z]+)?(_[0-9]+)?.(png|jpe?g|webp)$`);

    if(!availableAvatars.length) {
      availableAvatars = character.assets.matchFiles(`^Avatars/${folder}/(Neutral_)?${state}(_[0-9]+)?.(png|jpe?g|webp)$`);
    }

    log(() => availableAvatars.length + " avatars found in folder " + folder + " for expression " + expression + " and state " + state);

    return availableAvatars;
  } else {
    // List root avatars
    let availableAvatars = character.assets.matchFiles(`^Avatars/(Default/)?${expression}_${state}(_[A-Z][a-z]+)?(_[0-9]+)?.(png|jpe?g|webp)$`);

    if(!availableAvatars.length) {
      availableAvatars = character.assets.matchFiles(`^Avatars/(Default/)?(Neutral_)?${state}(_[0-9]+)?.(png|jpe?g|webp)$`);
    }

    log(() => availableAvatars.length + " avatars found for expression " + expression + " and state " + state);

    return availableAvatars;
  }
}

/**
 * Changes the current avatar using the last expression
 * @param {Character} character - The character
 * @param {string} state - The state string (Idle, Thinking, Talking)
 */
export function applyAvatar(character, state) {
  log(() => "Avatar applying for character " + character.name + " and state " + state);

  if(!stateStore.canSwitch(character, state)) {
    log(() => "Avatar cannot switch");
    return;
  }

  // Find applicable avatars
  let avatars = getAvatars(character, state);

  // When there are no available avatars, do nothing
  if (!avatars.length) {
    return;
  }

  // Apply one of the avatars
  if(avatars.length > 1 && lastAvatar.value) {
    avatars = avatars.filter(a => a != lastAvatar.value);
  }
  const avatar = randomly(avatars);
  lastAvatar.value = avatar;
  chat.appTrigger("SetAvatar", avatar, character.id);
  stateStore.store(character, state, avatar);

  log(() => "Avatar applied: " + avatar);
}"},{"name":"expressions","content":"import { chat } from "@voxta";
