/**
 * Returns the current expression of a character
 * @param {Character} character - The character
 */
export function getExpression(character) {
  return chat.variables["expression_" + character.id] || "Neutral";
}

/**
 * Returns the current expression of a character
 * @param {Character} character - The character
 * @param {string} expression - The character"s expression
 */
export function setExpression(character, expression) {
  log(() => "Expression set: " + expression);
  chat.variables["expression_" + character.id] = expression || "Neutral";
}"},{"name":"logging","content":"export function log(fn) {
