  // console.log(fn());
}"},{"name":"state","content":"import { chat } from "@voxta";

const avatarSuffixThatDisablesSwitchingWhileTalking = 'Fixed';
const minTimeBetweenSpeechLinesToAllowSwitching = 3;

class StateStore {
  speaking = false;
  characterStates = {};

  setSpeaking(value) {
    this.speaking = value;
  }

  store(character, newState, avatar) {
    if(typeof newState !== 'string') throw new Error('Invalid state value: ' + newState);

    let characterState = this.characterStates[character.id];
    if(!characterState) {
      characterState = {
        state: undefined,
        lastSpeakTime: undefined,
        avatar: undefined
      };
      this.characterStates[character.id] = characterState;
    }
    characterState.lastSpeakTime = (newState === 'Talking') ? chat.time : undefined;
    characterState.avatar = avatar;
    characterState.value = newState;
  }

  get(character) {
    return this.characterStates[character.id];
  }

  canSwitch(character, newState) {
    // Always switch when not speaking
    if(!this.speaking) {
      return true;
    }
    const characterState = this.get(character);
    // Always switch the first time
    if(!characterState) {
      return true;
    }
    // Do not switch more often than every Xs
    if(characterState.lastSpeakTime && characterState.lastSpeakTime > chat.time + minTimeBetweenSpeechLinesToAllowSwitching) {
      return false;
    }
    // Do not switch if the avatar contains 'Fixed'
    if(newState === 'Talking' && characterState.avatar && characterState.avatar.indexOf(avatarSuffixThatDisablesSwitchingWhileTalking) > -1) {
      return false;
    }
    return true;
  }
}

export const stateStore = new StateStore();"},{"name":"api","content":"import { chat } from "@voxta";
import { stateStore } from "./state";
import { applyAvatar, setAvatarFolderName } from "./avatars";
import { log } from "./logging";

/**
 * Changes the default view for this chat
 * @param {string} view - portrait, talk or chat
 */
export function setView(view) {
  chat.variables.view = view;
  chat.appTrigger('SelectView', view);
}

/**
 * Defines a folder in which the avatar images should be selected from
 * @param {Character} character - The character to change the folder of
 * @param {string} folder - The name of the folder (Assets/Avatars/{folder})
 */
export function setAvatarFolder(character, folder) {
  if(!character) throw new Error('Expected a character for setAvatarFolder');
  log(() => 'Set avatar ' + folder + ' for ' + character.name);
  setAvatarFolderName(character, folder);
  const state = stateStore.get(character);
  applyAvatar(character, (state?.value) || 'Idle');
}

/**
 * Changes the background of the chat
 * @param {string} path - The scenario's asset path
 */
export function setBackground(path) {
  log(() => 'Set background ' + path);
  chat.variables.background = path;
  chat.appTrigger('SetBackgroundFromScenario', path);
}"}]

